SELECT 
    id, step_name, series_name, product_id, step_order, is_active, 
    description, created_at, updated_at, status, cloth_paper_id, 
    paper_type, step_id
FROM pre_processing_steps 
WHERE step_id = #{stepId} 
AND series_name = #{seriesName}
AND paper_type = #{paperType}
AND is_active = true
ORDER BY step_order ASC

